namespace sv_e59e115a84924a32b0406c60ea641cfd;

public enum Theme
{
    Light,
    Dark,
    System
}

public record ThemeInfo(Theme Theme, string AccentColor)
{
    public static ThemeInfo Default => new(Theme.Light, "#0d6efd");
}

@rendermode InteractiveServer

<span class="badge" style="background-color: @Theme?.AccentColor">
    @(Theme?.Theme.ToString() ?? "Light")
</span>

@code {
    [CascadingParameter]
    private ThemeInfo? Theme { get; set; }
}

@page "/settings"
@rendermode InteractiveServer
@inject CascadingValueSource<ThemeInfo> ThemeSource

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="mb-3">
    <label class="form-label">Theme</label>
    <select class="form-select" value="@Theme?.Theme" @onchange="OnThemeChanged">
        @foreach (var t in Enum.GetValues<Theme>())
        {
            <option value="@t">@t</option>
        }
    </select>
</div>

<div class="mb-3">
    <label class="form-label">Accent Color</label>
    <input type="color" class="form-control form-control-color"
           value="@(Theme?.AccentColor ?? "#0d6efd")"
           @onchange="OnAccentChanged" />
</div>

<div class="mt-3">
    <span>Current: </span>
    <span class="badge" style="background-color: @Theme?.AccentColor">
        @Theme?.Theme
    </span>
</div>

@code {
    [CascadingParameter]
    private ThemeInfo? Theme { get; set; }

    private async Task OnThemeChanged(ChangeEventArgs e)
    {
        var selected = Enum.Parse<Theme>(e.Value?.ToString() ?? "Light");
        await ThemeSource.NotifyChangedAsync(
            new ThemeInfo(selected, Theme?.AccentColor ?? "#0d6efd"));
    }

    private async Task OnAccentChanged(ChangeEventArgs e)
    {
        var color = e.Value?.ToString() ?? "#0d6efd";
        await ThemeSource.NotifyChangedAsync(
            new ThemeInfo(Theme?.Theme ?? Theme.Light, color));
    }
}

